 17	} from '@patternfly/react-core';
 18	import Helmet from 'react-helmet';
 19	import {
 20	  useK8sModel,
 21	  getGroupVersionKindForResource,
 22	  ResourceYAMLEditor,
 23	  useK8sWatchResource,
 24	  useActiveNamespace,
 25	} from '@openshift-console/dynamic-plugin-sdk';
 26	import './kuadrant.css';
 27	import { handleCancel } from '../utils/cancel';
 28	import { useHistory, useLocation } from 'react-router-dom';
 29	import yaml from 'js-yaml';
 30	import { useTranslation } from 'react-i18next';
 31	import ClusterIssuerSelect from './issuer/clusterIssuerSelect';
 32	import IssuerSelect from './issuer/issuerSelect';
 33	import { ClusterIssuer } from './issuer/types';
 34	import { Issuer } from './issuer/types';
 35	import { Gateway } from './gateway/types';
 36	import GatewaySelect from './gateway/GatewaySelect';
 37	import KuadrantCreateUpdate from './KuadrantCreateUpdate';
 38	import { K8sResourceCommon } from '@openshift-console/dynamic-plugin-sdk';
 39	import resourceGVKMapping from '../utils/latest';
 40	
 41	const KuadrantTLSCreatePage: React.FC = () => {
 42	  const history = useHistory();
 43	  const [policyName, setPolicyName] = React.useState('');
 44	  const [selectedNamespace] = useActiveNamespace();
 45	  const [selectedGateway, setSelectedGateway] = React.useState<Gateway>({
 46	    name: '',
 47	    namespace: '',
 48	  });
 49	  const [selectedClusterIssuers, setSelectedClusterIssuers] = React.useState<ClusterIssuer>({
 50	    name: '',
 51	  });
 52	  const [selectedIssuer, setSelectedIssuers] = React.useState<Issuer>({ name: '', namespace: '' });
 53	  const [certIssuerType, setCertIssuerType] = React.useState<'clusterissuer' | 'issuer'>(
 54	    'clusterissuer',
 55	  );
 56	  const { t } = useTranslation('plugin__kuadrant-console-plugin');
 57	  const location = useLocation();
 58	  const pathSplit = location.pathname.split('/');
 59	  const nameEdit = pathSplit[6];
 60	  const namespaceEdit = pathSplit[3];
 61	  const [formDisabled, setFormDisabled] = React.useState(false);
 62	  const [create, setCreate] = React.useState(true);
 63	  const [creationTimestamp, setCreationTimestamp] = React.useState('');
 64	  const [resourceVersion, setResourceVersion] = React.useState('');
 65	  let isFormValid = false;
 66	
 67	  // Creates TLS policy object to be used for form and yaml creation of the resource
 68	  const createTlsPolicy = () => ({
 69	    apiVersion:
 70	      resourceGVKMapping['TLSPolicy'].group + '/' + resourceGVKMapping['TLSPolicy'].version,
 71	    kind: resourceGVKMapping['TLSPolicy'].kind,
 72	    metadata: {
 73	      name: policyName,
 74	      namespace: selectedNamespace,
 75	      ...(creationTimestamp ? { creationTimestamp } : {}),
 76	      ...(resourceVersion ? { resourceVersion } : {}),
 77	    },
 78	    spec: {
 79	      targetRef: {
 80	        group: 'gateway.networking.k8s.io',
 81	        kind: 'Gateway',
 82	        name: selectedGateway.name,
 83	      },
 84	      issuerRef:
 85	        certIssuerType === 'clusterissuer'
 86	          ? {
 87	              name: selectedClusterIssuers.name,
 88	              kind: 'ClusterIssuer',
 89	            }
 90	          : {
 91	              name: selectedIssuer.name,
 92	              kind: 'Issuer',
 93	            },
 94	    },
 95	  });
 96	
 97	  const tlsPolicy = createTlsPolicy();
 98	  const tlsPolicyGVK = getGroupVersionKindForResource({
 99	    apiVersion: `${resourceGVKMapping['TLSPolicy'].group}/${resourceGVKMapping['TLSPolicy'].version}`,
100	    kind: resourceGVKMapping['TLSPolicy'].kind,
101	  });
102	  const [tlsPolicyModel] = useK8sModel({
103	    group: tlsPolicyGVK.group,
104	    version: tlsPolicyGVK.version,
105	    kind: tlsPolicyGVK.kind,
106	  });
107	
108	  // K8sResourceCommon by default does not contain spec etc which is needed for updating resource forms
109	  interface TLSPolicyEdit extends K8sResourceCommon {
110	    spec?: {
111	      targetRef?: {
112	        group?: string;
113	        kind?: string;
114	        name?: string;
115	      };
116	      issuerRef?: {
117	        kind?: 'ClusterIssuer' | 'Issuer';
118	        name?: string;
119	      };
120	    };
121	  }
122	
123	  //Checking if the policy already exists and is to be edited or if its new and is being created
124	  let tlsResource = null;
125	  if (nameEdit) {
126	    tlsResource = {
127	      groupVersionKind: tlsPolicyGVK,
128	      isList: false,
129	      name: nameEdit,
130	      namespace: namespaceEdit,
131	    };
132	  }
133	
134	  const [tlsData, tlsLoaded, tlsError] = tlsResource
135	    ? useK8sWatchResource(tlsResource)
136	    : [null, false, null]; //Syntax allows for tlsResource to be null in the case of a create
137	
138	  // When a resource is being updated setting the form from the yaml it gets from useK8sWatchResource
139	  React.useEffect(() => {
140	    if (tlsLoaded && !tlsError) {
141	      if (!Array.isArray(tlsData)) {
142	        const tlsPolicyUpdate = tlsData as TLSPolicyEdit;
