144	        setResourceVersion(tlsPolicyUpdate.metadata.resourceVersion);
145	        setFormDisabled(true);
146	        setCreate(false);
147	        setPolicyName(tlsPolicyUpdate.metadata?.name || '');
148	        setSelectedGateway({
149	          name: tlsPolicyUpdate.spec?.targetRef?.name || '',
150	          namespace: tlsPolicyUpdate.metadata?.namespace || '',
151	        });
152	        if (tlsPolicyUpdate.spec?.issuerRef?.kind === 'ClusterIssuer') {
153	          setCertIssuerType('clusterissuer');
154	          setSelectedClusterIssuers({ name: tlsPolicyUpdate.spec?.issuerRef?.name || '' });
