156	          setCertIssuerType('issuer');
157	          setSelectedIssuers({
158	            name: tlsPolicyUpdate.spec?.issuerRef?.name || '',
159	            namespace: tlsPolicyUpdate.metadata?.namespace || '',
160	          });
161	        }
