207	  const [view, setView] = React.useState('form');
208	
209	  // Policy Name
210	  const handleNameChange = (_event, policyName: string) => {
211	    setPolicyName(policyName);
212	  };
213	
214	  //Cancel
215	  const handleCancelResource = () => {
