233	        </title>
234	      </Helmet>
235	      <Page>
236	        <PageSection className="pf-m-no-padding" variant="light">
237	          <div className="co-m-nav-title">
238	            <Title headingLevel="h1">{create ? 'Create TLS Policy' : 'Edit TLS Policy'}</Title>
239	            <p className="help-block co-m-pane__heading-help-text">
240	              <div>
241	                {t(
242	                  'Targets Gateway API networking resources Gateways to provide TLS for gateway listeners by managing the lifecycle of TLS certificates using cert-manager',
243	                )}
244	              </div>
245	            </p>
246	          </div>
