248	            className="kuadrant-editor-toggle"
249	            role="radiogroup"
250	            isInline
251	            hasNoPaddingTop
252	            fieldId="create-type-radio-group"
253	            label={t('Configure via')}
254	          >
255	            <Flex alignItems={{ default: 'alignItemsCenter' }}>
256	              <FlexItem>
257	                <Radio
258	                  label={t('Form View')}
259	                  isChecked={view === 'form'}
