261	                  id="form-view"
262	                  name="view-toggle"
263	                />
264	              </FlexItem>
265	              <FlexItem>
266	                <Radio
267	                  label={t('YAML View')}
268	                  isChecked={view === 'yaml'}
269	                  onChange={() => setView('yaml')}
270	                  id="yaml-view"
271	                  name="view-toggle"
272	                />
273	              </FlexItem>
274	            </Flex>
275	          </FormGroup>
276	        </PageSection>
277	        {view === 'form' ? (
278	          <PageSection variant="light">
279	            <Form className="co-m-pane__form">
280	              <FormGroup label={t('Policy name')} isRequired fieldId="simple-form-policy-name-01">
281	                <TextInput
282	                  isRequired
283	                  type="text"
284	                  id="simple-form-policy-name-01"
285	                  name="simple-form-policy-name-01"
286	                  aria-describedby="simple-form-policy-name-01-helper"
287	                  value={policyName}
288	                  onChange={handleNameChange}
289	                  isDisabled={formDisabled}
290	                  placeholder={t('Policy name')}
291	                />
292	                <FormHelperText>
293	                  <HelperText>
294	                    <HelperTextItem>{t('Unique name of the TLSPolicy.')}</HelperTextItem>
295	                  </HelperText>
296	                </FormHelperText>
297	              </FormGroup>
298	              <GatewaySelect selectedGateway={selectedGateway} onChange={setSelectedGateway} />
299	              <FormGroup
300	                role="radiogroup"
301	                isInline
302	                fieldId="cert-manager-issuer"
303	                label={t('Cert manager issuer type')}
304	                isRequired
305	                aria-labelledby="issuer-label"
306	              >
307	                <Radio
308	                  label={t('Cluster issuer')}
309	                  isChecked={certIssuerType === 'clusterissuer'}
310	                  onChange={() => {
311	                    setCertIssuerType('clusterissuer');
312	                  }}
313	                  id="cluster-issuer"
314	                  name="issuer"
315	                />
316	                <Radio
317	                  label={t('Issuer')}
318	                  isChecked={certIssuerType === 'issuer'}
319	                  onChange={() => {
320	                    setCertIssuerType('issuer');
321	                  }}
322	                  id="issuer"
323	                  name="issuer"
324	                />
325	              </FormGroup>
326	              {certIssuerType === 'clusterissuer' ? (
327	                <ClusterIssuerSelect
328	                  selectedClusterIssuer={selectedClusterIssuers}
329	                  onChange={setSelectedClusterIssuers}
330	                />
331	              ) : (
332	                <IssuerSelect selectedIssuer={selectedIssuer} onChange={setSelectedIssuers} />
333	              )}
334	              <ActionGroup className="pf-u-mt-0">
335	                <KuadrantCreateUpdate
336	                  model={tlsPolicyModel}
337	                  resource={tlsPolicy}
338	                  policyType="tls"
339	                  history={history}
340	                  validation={isFormValid}
341	                />
342	                <Button variant="link" onClick={handleCancelResource}>
343	                  {t('Cancel')}
344	                </Button>
345	              </ActionGroup>
346	            </Form>
347	          </PageSection>
348	        ) : (
349	          <React.Suspense fallback={<div> {t('Loading..')}.</div>}>
350	            <ResourceYAMLEditor
351	              initialResource={yamlInput}
352	              create={create}
353	              onChange={handleYAMLChange}
354	            ></ResourceYAMLEditor>
355	          </React.Suspense>
356	        )}
357	      </Page>
358	    </>
359	  );
360	};
361	
362	export default KuadrantTLSCreatePage;

